/* Fix the gradient syntax errors:
   - Linear: should go from blue to purple (left to right)
   - Radial: should be a circle from yellow center to orange edge
   - Conic: should show a rainbow color wheel */
.banner {
  padding: 40px;
  margin: 8px;
  color: white;
  font-weight: bold;
  text-align: center;
  border-radius: 8px;
}
.linear-banner {
  background: linear-gradient(blue, purple); /* wrong direction */
}
.radial-banner {
  background: radial-gradient(yellow, orange); /* should be circle */
}
.conic-banner {
  background: linear-gradient(red, orange, yellow, green, blue, purple); /* wrong type */
}

